function collectionsHash(collections: IconCollection[]): string {
  const hash = createHash("sha256");
  for (const collection of collections) {
    hash.update(collection.prefix);
    hash.update(
      Object.keys(collection.icons)
        .concat(Object.keys(collection.aliases ?? {}))
        .sort()
        .join(","),
    );
  }
  return hash.digest("hex");
}

export function tryStatSync(file: string): fs.Stats | undefined {
	try {
		// The "throwIfNoEntry" is a performance optimization for cases where the file does not exist
		return fs.statSync(file, { throwIfNoEntry: false });
	} catch {
		// Ignore errors
	}
}

export function isFileReadable(filename: string): boolean {
	if (!tryStatSync(filename)) {
		return false;
	}

	try {
		// Check if current process has read permission to the file
		fs.accessSync(filename, fs.constants.R_OK);

		return true;
	} catch {
		return false;
	}
}

handle(apiContext: APIContext, state: FetchState): Promise<Response | undefined> | undefined {
	state.pipeline.usedFeatures |= PipelineFeatures.actions;
	if (apiContext.isPrerendered) {
		return undefined;
	}

	const { action, setActionResult } = getActionContext(apiContext);
	if (!action) {
		return undefined;
	}

	return this.#executeAction(action, setActionResult);
}

function handleFormDataGet(
	key: string,
	formData: FormData,
	validator: unknown,
	baseValidator: unknown,
) {
	const value = formData.get(key);
	if (!value) {
		return baseValidator instanceof z.$ZodOptional ? undefined : null;
	}
	return validator instanceof z.$ZodNumber ? Number(value) : value;
}

async function parseFormInput(inputSchema: z.$ZodType, unparsedInput: FormData) {
	const baseSchema = unwrapBaseZ4ObjectSchema(inputSchema, unparsedInput);
	const input =
		baseSchema instanceof z.$ZodObject
			? formDataToObject(unparsedInput, baseSchema)
			: unparsedInput;

	const parsed = await z.safeParseAsync(inputSchema, input);
	return parsed;
}

function createPrettyError(err: Error) {
	err.message = `Astro could not update your astro.config.js file safely.
Reason: ${err.message}

You will need to add these integration(s) manually.
Documentation: https://docs.astro.build/en/guides/integrations/`;
	return err;
}

constructor({
	logger,
	textStyler,
	astroVersionProvider,
	flags,
}: {
	logger: AstroLogger;
	textStyler: TextStyler;
	astroVersionProvider: AstroVersionProvider;
	flags: Flags;
}) {
	this.#logger = logger;
	this.#textStyler = textStyler;
	this.#astroVersionProvider = astroVersionProvider;
	this.#flags = flags;
}

async function resetPreference(
	settings: AstroSettings,
	key: PreferenceKey,
	{ location }: SubcommandOptions,
) {
	try {
		await settings.preferences.set(key, undefined as any, { location });
		console.log(msg.preferenceReset(key));
		return 0;
	} catch {}
	return 1;
}

static create({
	logger,
	manifest,
	renderers,
	resolve,
	streaming,
}: Pick<ContainerPipeline, 'logger' | 'manifest' | 'renderers' | 'resolve' | 'streaming'>) {
	return new ContainerPipeline(logger, manifest, 'development', renderers, resolve, streaming);
}

constructor({
	settings,
	logger,
	store,
	watcher,
	contentConfigObserver = globalContentConfigObserver,
}: ContentLayerOptions) {
	this.#logger = logger;
	this.#store = store;
	this.#settings = settings;
	this.#contentConfigObserver = contentConfigObserver;
	if (watcher) {
		this.#watcher = createWatcherWrapper(watcher);
	}
	this.#queue = new PQueue({ concurrency: 1 });
}

export function deserializeRouteInfo(rawRouteInfo: SerializedRouteInfo): RouteInfo {
	return {
		styles: rawRouteInfo.styles,
		file: rawRouteInfo.file,
		links: rawRouteInfo.links,
		scripts: rawRouteInfo.scripts,
		routeData: deserializeRouteData(rawRouteInfo.routeData),
	};
}

function makeRequestHeaders(req: NodeRequest): Headers {
	const headers = new Headers();
	for (const [name, value] of Object.entries(req.headers)) {
		if (value === undefined) {
			continue;
		}
		if (Array.isArray(value)) {
			for (const item of value) {
				headers.append(name, item);
			}
		} else {
			headers.append(name, value);
		}
	}
	return headers;
}

export async function loadManifest(rootFolder: URL): Promise<SSRManifest> {
	const manifestFile = new URL('./manifest.json', rootFolder);
	const rawManifest = await fs.promises.readFile(manifestFile, 'utf-8');
	const serializedManifest: SerializedSSRManifest = JSON.parse(rawManifest);
	return deserializeManifest(serializedManifest);
}

async getLogger(): Promise<AstroLogger> {
	if (this.resolvedLogger) {
		return this.logger;
	}
	this.resolvedLogger = true;
	if (this.manifest.experimentalLogger) {
		this.logger = await loadLogger(this.manifest.experimentalLogger);
	}
	return this.logger;
}

export function extractCacheRoutesFromRouteRules(
	routeRules: AstroConfig['experimental']['routeRules'],
): Record<string, CacheOptions> | undefined {
	if (!routeRules) return undefined;

	const cacheRoutes: Record<string, CacheOptions> = {};

	for (const [pattern, rule] of Object.entries(routeRules)) {
		const cacheOptions = normalizeRouteRuleCacheOptions(rule);
		if (cacheOptions) {
			cacheRoutes[pattern] = cacheOptions;
		}
	}

	return Object.keys(cacheRoutes).length > 0 ? cacheRoutes : undefined;
}

function normalizeFilename(filename: string, root: URL) {
	const normalizedFilename = normalizePath(filename);
	const normalizedRoot = normalizePath(fileURLToPath(root));
	if (normalizedFilename.startsWith(normalizedRoot)) {
		return normalizedFilename.slice(normalizedRoot.length - 1);
	} else {
		return normalizedFilename;
	}
}

#parse() {
	const raw = this.#request.headers.get('cookie');
	if (!raw) {
		return;
	}
	// Pass identity function for decoding so it doesn't use the default.
	// We'll do the actual decoding when we read the value.
	this.#requestValues = parse(raw, { decode: identity });
}

export async function startContainer({
	settings,
	viteServer,
	logger,
}: Container): Promise<AddressInfo> {
	const { port } = settings.config.server;
	await viteServer.listen(port);
	const devServerAddressInfo = viteServer.httpServer!.address() as AddressInfo;
	await runHookServerStart({
		config: settings.config,
		address: devServerAddressInfo,
		logger,
	});

	return devServerAddressInfo;
}

createLink(text: string, href: string | undefined): HTMLDivElement {
	const linkContainer = document.createElement('div');
	const linkElement = href ? document.createElement('a') : document.createElement('button');
	linkElement.innerHTML = text;

	if (href && linkElement instanceof HTMLAnchorElement) {
		linkElement.href = href;
		linkElement.target = '_blank';
	}

	linkContainer.appendChild(linkElement);
	linkContainer.className = 'link';

	return linkContainer;
}

renderWithOptions(request: Request, options: ResolvedRenderOptions): Promise<Response> {
	if (!this.#app) {
		const app = Reflect.get(request, appSymbol) as BaseApp<Pipeline> | undefined;
		if (!app) {
			throw new Error('No fetch handler provided.');
		}
		this.#app = app;
		this.#handler = new AstroHandler(app);
	}
	const state = new FetchState(this.#app.pipeline, request, options);
	return this.#handler!.handle(state);
}

#computePathname(url: URL): string {
	let pathname = collapseDuplicateLeadingSlashes(url.pathname);
	const base = this.pipeline.manifest.base;
	if (pathname.startsWith(base)) {
		const baseWithoutTrailingSlash = removeTrailingForwardSlash(base);
		pathname = pathname.slice(baseWithoutTrailingSlash.length + 1);
	}
	pathname = prependForwardSlash(pathname);
	try {
		return decodeURI(pathname);
	} catch (e: any) {
		this.pipeline.logger.error(null, e.toString());
		return pathname;
	}
}

function getApp(request: Request): BaseApp<Pipeline> {
	const app = Reflect.get(request, appSymbol) as BaseApp<Pipeline> | undefined;
	if (!app) {
		throw new Error(
			'FetchState(request) called on a request without an attached app. ' +
				"Ensure it runs inside Astro's request pipeline.",
		);
	}
	return app;
}

export function astro(state: FetchState): Promise<Response> {
	const app = getApp(state.request);
	let handler = astroHandlers.get(app);
	if (!handler) {
		handler = new AstroHandler(app);
		astroHandlers.set(app, handler);
	}
	return handler.handle(state);
}

export function trailingSlash(state: FetchState): Response | undefined {
	const app = getApp(state.request);
	let handler = trailingSlashHandlers.get(app);
	if (!handler) {
		handler = new TrailingSlashHandler(app);
		trailingSlashHandlers.set(app, handler);
	}
	return handler.handle(state);
}

export function pages(state: FetchState): Promise<Response> {
	const app = getApp(state.request);
	let handler = pagesHandlers.get(app);
	if (!handler) {
		handler = new PagesHandler(app.pipeline);
		pagesHandlers.set(app, handler);
	}
	return handler.handle(state, state.getAPIContext());
}

export function createNodeLoggerFromFlags(inlineConfig: AstroInlineConfig): AstroLogger {
	if (inlineConfig.logger) return inlineConfig.logger;

	return new AstroLogger({
		destination: nodeLogDestination(),
		level: inlineConfig.logLevel ?? 'info',
	});
}

export function telemetryNotice() {
	const headline = blue(`▶ Astro collects anonymous usage data.`);
	const why = '  This information helps us improve Astro.';
	const disable = `  Run "astro telemetry disable" to opt-out.`;
	const details = `  ${cyan(underline('https://astro.build/telemetry'))}`;
	return [headline, why, disable, details].join('\n');
}

async execute(state: FetchState, payload: RewritePayload): Promise<Response> {
	const pipeline = state.pipeline;
	pipeline.logger.debug('router', 'Calling rewrite: ', payload);
	const result = await pipeline.tryRewrite(payload, state.request);
	applyRewriteToState(state, payload, result, { mergeCookies: true });

	const middleware = new AstroMiddleware(pipeline);
	const pagesHandler = new PagesHandler(pipeline);
	return middleware.handle(state, pagesHandler.handle.bind(pagesHandler));
}
